use std::collections::HashSet;

struct UserActivityService {
    db_connection: String,
}

impl UserActivityService {
    fn new(conn: &str) -> Self {
        UserActivityService { db_connection: conn.to_string() }
    }

    async fn check_all_active(&self, user_ids: Vec<i32>) -> bool {
        if user_ids.is_empty() {
            return true;
        }

        let id_set: HashSet<i32> = user_ids.into_iter().collect();

        println!("Simulating database check for IDs: {:?}", id_set);

        let mut active_count = 0;
        for &id in id_set.iter() {
            if id % 2 == 0 {
                active_count += 1;
            }
        }

        active_count > 0
    }
}

#[tokio::main]
async fn main() {
    let service = UserActivityService::new("mock_connection_string");

    let ids1 = vec![10, 21, 32];
    let result1 = service.check_all_active(ids1).await;
    println!("Result for [10, 21, 32]: {}", result1);

    let ids2 = vec![5, 7, 9];
    let result2 = service.check_all_active(ids2).await;
    println!("Result for [5, 7, 9]: {}", result2);
}
